const express = require('express');
const crypto = require('crypto');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const { body, param, validationResult } = require('express-validator');
const jwt = require('jsonwebtoken');

const app = express();

// Security middleware
app.use(helmet());
app.use(express.json({ limit: '10kb' }));

// Rate limiting
const generalLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' }
});

const completionLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 10,
  message: { error: 'Too many level completion requests.' }
});

app.use(generalLimiter);

// --- In-memory stores (replace with a real database in production) ---
const JWT_SECRET = process.env.JWT_SECRET || crypto.randomBytes(64).toString('hex');
const HMAC_SECRET = process.env.HMAC_SECRET || crypto.randomBytes(64).toString('hex');

const users = new Map();
const levelCompletions = new Map();
const claimedRewards = new Map();
const pendingRewards = new Map();

// --- Level configuration (server-authoritative) ---
const LEVEL_CONFIG = {
  1: { maxScore: 1000, minTime: 10, maxTime: 300, stars3: 800, stars2: 500, stars1: 200 },
  2: { maxScore: 1500, minTime: 15, maxTime: 400, stars3: 1200, stars2: 750, stars1: 300 },
  3: { maxScore: 2000, minTime: 20, maxTime: 500, stars3: 1600, stars2: 1000, stars1: 400 },
  4: { maxScore: 2500, minTime: 25, maxTime: 600, stars3: 2000, stars2: 1250, stars1: 500 },
  5: { maxScore: 3000, minTime: 30, maxTime: 700, stars3: 2400, stars2: 1500, stars1: 600 },
};

const REWARD_TABLE = {
  1: { coins: 50, gems: 1 },
  2: { coins: 75, gems: 2 },
  3: { coins: 100, gems: 5 },
};

// --- Helper functions ---

function generateSessionToken() {
  return crypto.randomBytes(32).toString('hex');
}

function computePayloadHmac(payload) {
  const sorted = JSON.stringify(payload, Object.keys(payload).sort());
  return crypto.createHmac('sha256', HMAC_SECRET).update(sorted).digest('hex');
}

function validateClientChecksum(payload, clientChecksum) {
  const expected = computePayloadHmac(payload);
  return crypto.timingSafeEqual(Buffer.from(expected, 'hex'), Buffer.from(clientChecksum, 'hex'));
}

function sanitizeString(str) {
  if (typeof str !== 'string') return '';
  return str.replace(/[<>&"']/g, '').trim().substring(0, 100);
}

function calculateStars(score, levelConfig) {
  if (score >= levelConfig.stars3) return 3;
  if (score >= levelConfig.stars2) return 2;
  if (score >= levelConfig.stars1) return 1;
  return 0;
}

function detectAnomalies(userId, levelId, score, timeSeconds) {
  const config = LEVEL_CONFIG[levelId];
  const issues = [];

  if (score > config.maxScore) {
    issues.push(`Score ${score} exceeds maximum ${config.maxScore}`);
  }
  if (score < 0) {
    issues.push('Negative score');
  }
  if (timeSeconds < config.minTime) {
    issues.push(`Completion time ${timeSeconds}s below minimum ${config.minTime}s`);
  }
  if (timeSeconds > config.maxTime) {
    issues.push(`Completion time ${timeSeconds}s exceeds maximum ${config.maxTime}s`);
  }
  if (!Number.isInteger(score)) {
    issues.push('Score is not an integer');
  }

  // Check for rapid repeated completions
  const userCompletions = levelCompletions.get(userId) || [];
  const recentCompletions = userCompletions.filter(
    c => c.levelId === levelId && (Date.now() - c.timestamp) < 60000
  );
  if (recentCompletions.length >= 3) {
    issues.push('Suspicious rapid completion rate');
  }

  // Check for score consistency - sudden huge jumps
  const previousBest = userCompletions
    .filter(c => c.levelId === levelId)
    .reduce((max, c) => Math.max(max, c.serverValidatedScore), 0);
  if (previousBest > 0 && score > previousBest * 2) {
    issues.push(`Score jump suspicious: previous best ${previousBest}, claimed ${score}`);
  }

  return issues;
}

// --- Authentication middleware ---

function authenticateToken(req, res, next) {
  const authHeader = req.headers['authorization'];
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  const token = authHeader.split(' ')[1];

  try {
    const decoded = jwt.verify(token, JWT_SECRET, {
      algorithms: ['HS256'],
      maxAge: '24h'
    });

    const user = users.get(decoded.userId);
    if (!user) {
      return res.status(401).json({ error: 'User not found' });
    }

    req.userId = decoded.userId;
    req.user = user;
    next();
  } catch (err) {
    if (err.name === 'TokenExpiredError') {
      return res.status(401).json({ error: 'Token expired' });
    }
    return res.status(401).json({ error: 'Invalid token' });
  }
}

// --- Validation error handler ---

function handleValidationErrors(req, res, next) {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({
      error: 'Validation failed',
      details: errors.array().map(e => ({ field: e.path, message: e.msg }))
    });
  }
  next();
}

// --- Routes ---

// Register / Login (simplified for demo)
app.post('/api/auth/register',
  body('username').isString().isLength({ min: 3, max: 30 }).matches(/^[a-zA-Z0-9_]+$/),
  body('deviceId').isString().isLength({ min: 10, max: 128 }),
  handleValidationErrors,
  (req, res) => {
    const { username, deviceId } = req.body;
    const sanitizedUsername = sanitizeString(username);

    // Check for duplicate username
    for (const [, user] of users) {
      if (user.username === sanitizedUsername) {
        return res.status(409).json({ error: 'Username already taken' });
      }
    }

    const userId = crypto.randomUUID();
    const user = {
      userId,
      username: sanitizedUsername,
      deviceId: crypto.createHash('sha256').update(deviceId).digest('hex'),
      coins: 0,
      gems: 0,
      highestLevelUnlocked: 1,
      createdAt: Date.now(),
      flagged: false
    };

    users.set(userId, user);
    levelCompletions.set(userId, []);
    claimedRewards.set(userId, new Set());
    pendingRewards.set(userId, new Map());

    const token = jwt.sign({ userId }, JWT_SECRET, {
      algorithm: 'HS256',
      expiresIn: '24h'
    });

    res.status(201).json({
      token,
      userId,
      username: sanitizedUsername,
      hmacSecret: HMAC_SECRET // In production, embed this in the client binary securely
    });
  }
);

app.post('/api/auth/login',
  body('username').isString().isLength({ min: 3, max: 30 }),
  body('deviceId').isString().isLength({ min: 10, max: 128 }),
  handleValidationErrors,
  (req, res) => {
    const { username, deviceId } = req.body;
    const sanitizedUsername = sanitizeString(username);
    const hashedDevice = crypto.createHash('sha256').update(deviceId).digest('hex');

    let foundUser = null;
    for (const [, user] of users) {
      if (user.username === sanitizedUsername && user.deviceId === hashedDevice) {
        foundUser = user;
        break;
      }
    }

    if (!foundUser) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const token = jwt.sign({ userId: foundUser.userId }, JWT_SECRET, {
      algorithm: 'HS256',
      expiresIn: '24h'
    });

    res.json({
      token,
      userId: foundUser.userId,
      username: foundUser.username,
      coins: foundUser.coins,
      gems: foundUser.gems,
      highestLevelUnlocked: foundUser.highestLevelUnlocked
    });
  }
);

// Start a level session (server tracks when level started)
app.post('/api/levels/:levelId/start',
  authenticateToken,
  param('levelId').isInt({ min: 1, max: Object.keys(LEVEL_CONFIG).length }),
  handleValidationErrors,
  (req, res) => {
    const levelId = parseInt(req.params.levelId, 10);
    const user = req.user;

    if (levelId > user.highestLevelUnlocked) {
      return res.status(403).json({ error: 'Level not unlocked' });
    }

    if (user.flagged) {
      return res.status(403).json({ error: 'Account under review' });
    }

    const sessionToken = generateSessionToken();
    const sessionData = {
      sessionToken,
      levelId,
      userId: req.userId,
      startedAt: Date.now(),
      used: false
    };

    // Store session (keyed by userId + levelId for simplicity)
    if (!user._activeSessions) user._activeSessions = new Map();
    user._activeSessions.set(`${levelId}`, sessionData);

    res.json({
      sessionToken,
      levelId,
      serverTime: Date.now()
    });
  }
);

// Complete a level
app.post('/api/levels/:levelId/complete',
  authenticateToken,
  completionLimiter,
  param('levelId').isInt({ min: 1, max: Object.keys(LEVEL_CONFIG).length }),
  body('score').isInt({ min: 0, max: 100000 }),
  body('timeSeconds').isFloat({ min: 0, max: 3600 }),
  body('sessionToken').isString().isLength({ min: 64, max: 64 }),
  body('checksum').isString().isLength({ min: 64, max: 64 }),
  body('moves').optional().isInt({ min: 0, max: 100000 }),
  handleValidationErrors,
  (req, res) => {
    const levelId = parseInt(req.params.levelId, 10);
    const { score, timeSeconds, sessionToken, checksum, moves } = req.body;
    const user = req.user;
    const userId = req.userId;

    if (user.flagged) {
      return res.status(403).json({ error: 'Account under review' });
    }

    const config = LEVEL_CONFIG[levelId];
    if (!config) {
      return res.status(400).json({ error: 'Invalid level' });
    }

    if (levelId > user.highestLevelUnlocked) {
      return res.status(403).json({ error: 'Level not unlocked' });
    }

    // Validate session token
    if (!user._activeSessions || !user._activeSessions.has(`${levelId}`)) {
      return res.status(400).json({ error: 'No active session for this level. Call /start first.' });
    }

    const session = user._activeSessions.get(`${levelId}`);

    if (session.used) {
      return res.status(400).json({ error: 'Session already used' });
    }

    if (!crypto.timingSafeEqual(Buffer.from(session.sessionToken, 'hex'), Buffer.from(sessionToken, 'hex'))) {
      return res.status(400).json({ error: 'Invalid session token' });
    }

    // Verify server-side elapsed time
    const serverElapsed = (Date.now() - session.startedAt) / 1000;
    const timeDrift = Math.abs(serverElapsed - timeSeconds);
    if (timeDrift > 5) {
      // Allow 5 seconds drift for network latency
      console.warn(`[ANOMALY] User ${userId} level ${levelId}: time drift ${timeDrift}s (server: ${serverElapsed}s, client: ${timeSeconds}s)`);
    }

    // Validate checksum (client integrity check)
    const checksumPayload = { score, timeSeconds, levelId, sessionToken };
    try {
      if (!validateClientChecksum(checksumPayload, checksum)) {
        console.warn(`[SECURITY] User ${userId}: checksum mismatch on level ${levelId}`);
        return res.status(400).json({ error: 'Data integrity check failed' });
      }
    } catch (err) {
      return res.status(400).json({ error: 'Invalid checksum format' });
    }

    // Mark session as used
    session.used = true;

    // Server-side validation and clamping
    const clampedScore = Math.min(Math.max(Math.floor(score), 0), config.maxScore);
    const clampedTime = Math.max(timeSeconds, config.minTime);

    // Anomaly detection
    const anomalies = detectAnomalies(userId, levelId, score, timeSeconds);
    if (anomalies.length > 0) {
      console.warn(`[ANOMALY] User ${userId} level ${levelId}:`, anomalies);

      // If severe anomalies, flag the account
      const severeAnomalies = anomalies.filter(a =>
        a.includes('Negative') || a.includes('exceeds maximum') || a.includes('below minimum') || a.includes('Suspicious rapid')
      );
      if (severeAnomalies.length > 0) {
        user.flagged = true;
        console.error(`[FLAGGED] User ${userId} flagged for: ${severeAnomalies.join('; ')}`);
        return res.status(400).json({ error: 'Completion data rejected' });
      }
    }

    // Calculate stars (server-authoritative)
    const stars = calculateStars(clampedScore, config);

    if (stars === 0) {
      return res.json({
        success: false,
        message: 'Level not passed. Minimum score not reached.',
        score: clampedScore,
        stars: 0
      });
    }

    // Record completion
    const completionRecord = {
      completionId: crypto.randomUUID(),
      levelId,
      clientReportedScore: score,
      serverValidatedScore: clampedScore,
      clientReportedTime: timeSeconds,
      serverMeasuredTime: serverElapsed,
      moves: moves ? Math.floor(moves) : null,
      stars,
      timestamp: Date.now(),
      anomalies: anomalies.length > 0 ? anomalies : undefined
    };

    const userCompletions = levelCompletions.get(userId);
    userCompletions.push(completionRecord);

    // Unlock next level if applicable
    const nextLevel = levelId + 1;
    if (nextLevel <= Object.keys(LEVEL_CONFIG).length && nextLevel > user.highestLevelUnlocked) {
      user.highestLevelUnlocked = nextLevel;
    }

    // Calculate reward (server-authoritative based on stars)
    const baseReward = REWARD_TABLE[stars] || REWARD_TABLE[1];
    const reward = {
      rewardId: crypto.randomUUID(),
      coins: baseReward.coins,
      gems: baseReward.gems,
      bonusCoins: 0,
      levelId,
      stars,
      createdAt: Date.now(),
      claimed: false
    };

    // Time bonus (server-measured time)
    if (serverElapsed < config.minTime * 2) {
      reward.bonusCoins = Math.floor(baseReward.coins * 0.25);
    }

    // Check if user already has a better completion for this level
    const previousBestStars = userCompletions
      .filter(c => c.levelId === levelId && c !== completionRecord)
      .reduce((max, c) => Math.max(max, c.stars), 0);

    // Only award new reward if this is a better result
    if (stars > previousBestStars) {
      const userPendingRewards = pendingRewards.get(userId);
      userPendingRewards.set(reward.rewardId, reward);
    }

    res.json({
      success: true,
      completionId: completionRecord.completionId,
      score: clampedScore,
      stars,
      isNewBest: stars > previousBestStars,
      reward: stars > previousBestStars ? {
        rewardId: reward.rewardId,
        coins: reward.coins + reward.bonusCoins,
        gems: reward.gems
      } : null,
      highestLevelUnlocked: user.highestLevelUnlocked,
      serverTime: Date.now()
    });
  }
);

// Get pending rewards
app.get('/api/rewards/pending',
  authenticateToken,
  (req, res) => {
    const userId = req.userId;
    const userPendingRewards = pendingRewards.get(userId);

    if (!userPendingRewards) {
      return res.json({ rewards: [] });
    }

    const rewardsList = [];
    for (const [, reward] of userPendingRewards) {
      if (!reward.claimed) {
        rewardsList.push({
          rewardId: reward.rewardId,
          levelId: reward.levelId,
          stars: reward.stars,
          coins: reward.coins + reward.bonusCoins,
          gems: reward.gems,
          createdAt: reward.createdAt
        });
      }
    }

    res.json({ rewards: rewardsList });
  }
);

// Claim a specific reward
app.post('/api/rewards/:rewardId/claim',
  authenticateToken,
  param('rewardId').isUUID(),
  handleValidationErrors,
  (req, res) => {
    const userId = req.userId;
    const { rewardId } = req.params;
    const user = req.user;

    if (user.flagged) {
      return res.status(403).json({ error: 'Account under review' });
    }

    const userPendingRewards = pendingRewards.get(userId);
    const userClaimedRewards = claimedRewards.get(userId);

    if (!userPendingRewards || !userPendingRewards.has(rewardId)) {
      return res.status(404).json({ error: 'Reward not found' });
    }

    const reward = userPendingRewards.get(rewardId);

    if (reward.claimed) {
      return res.status(409).json({ error: 'Reward already claimed' });
    }

    if (userClaimedRewards.has(rewardId)) {
      return res.status(409).json({ error: 'Reward already claimed' });
    }

    // Expire old rewards (24 hours)
    if (Date.now() - reward.createdAt > 24 * 60 * 60 * 1000) {
      userPendingRewards.delete(rewardId);
      return res.status(410).json({ error: 'Reward expired' });
    }

    // Award the reward (atomic operation in production with DB transactions)
    const totalCoins = reward.coins + reward.bonusCoins;
    const totalGems = reward.gems;

    // Overflow protection
    const newCoins = user.coins + totalCoins;
    const newGems = user.gems + totalGems;

    if (newCoins > Number.MAX_SAFE_INTEGER || newGems > Number.MAX_SAFE_INTEGER) {
      return res.status(400).json({ error: 'Currency overflow' });
    }

    user.coins = newCoins;
    user.gems = newGems;

    reward.claimed = true;
    reward.claimedAt = Date.now();
    userClaimedRewards.add(rewardId);
    userPendingRewards.delete(rewardId);

    res.json({
      success: true,
      rewardId,
      awarded: {
        coins: totalCoins,
        gems: totalGems
      },
      balance: {
        coins: user.coins,
        gems: user.gems
      },
      claimedAt: reward.claimedAt
    });
  }
);

// Claim all pending rewards
app.post('/api/rewards/claim-all',
  authenticateToken,
  (req, res) => {
    const userId = req.userId;
    const user = req.user;

    if (user.flagged) {
      return res.status(403).json({ error: 'Account under review' });
    }

    const userPendingRewards = pendingRewards.get(userId);
    const userClaimedRewards = claimedRewards.get(userId);

    if (!userPendingRewards || userPendingRewards.size === 0) {
      return res.json({ success: true, claimed: 0, balance: { coins: user.coins, gems: user.gems } });
    }

    let totalCoins = 0;
    let totalGems = 0;
    const claimedIds = [];
    const now = Date.now();

    for (const [rewardId, reward] of userPendingRewards) {
      if (reward.claimed || userClaimedRewards.has(rewardId)) continue;
      if (now - reward.createdAt > 24 * 60 * 60 * 1000) {
        userPendingRewards.delete(rewardId);
        continue;
      }

      totalCoins += reward.coins + reward.bonusCoins;
      totalGems += reward.gems;
      reward.claimed = true;
      reward.claimedAt = now;
      userClaimedRewards.add(rewardId);
      claimedIds.push(rewardId);
    }

    // Overflow protection
    if (user.coins + totalCoins > Number.MAX_SAFE_INTEGER || user.gems + totalGems > Number.MAX_SAFE_INTEGER) {
      // Rollback
      for (const rewardId of claimedIds) {
        const reward = userPendingRewards.get(rewardId);
        if (reward) {
          reward.claimed = false;
          delete reward.claimedAt;
        }
        userClaimedRewards.delete(rewardId);
      }
      return res.status(400).json({ error: 'Currency overflow' });
    }

    user.coins += totalCoins;
    user.gems += totalGems;

    // Clean up claimed rewards from pending
    for (const rewardId of claimedIds) {
      userPendingRewards.delete(rewardId);
    }

    res.json({
      success: true,
      claimed: claimedIds.length,
      awarded: {
        coins: totalCoins,
        gems: totalGems
      },
      balance: {
        coins: user.coins,
        gems: user.gems
      }
    });
  }
);

// Get player profile / progress
app.get('/api/profile',
  authenticateToken,
  (req, res) => {
    const user = req.user;
    const userId = req.userId;
    const userCompletions = levelCompletions.get(userId) || [];

    // Build level progress summary
    const levelProgress = {};
    for (const completion of userCompletions) {
      const existing = levelProgress[completion.levelId];
      if (!existing || completion.stars > existing.bestStars) {
        levelProgress[completion.levelId] = {
          levelId: completion.levelId,
          bestScore: completion.serverValidatedScore,
          bestStars: completion.stars,
          completions: (existing ? existing.completions : 0) + 1
        };
      } else {
        levelProgress[completion.levelId].completions += 1;
        if (completion.serverValidatedScore > existing.bestScore) {
          levelProgress[completion.levelId].bestScore = completion.serverValidatedScore;
        }
      }
    }

    res.json({
      userId,
      username: user.username,
      coins: user.coins,
      gems: user.gems,
      highestLevelUnlocked: user.highestLevelUnlocked,
      totalCompletions: userCompletions.length,
      levelProgress: Object.values(levelProgress),
      pendingRewards: (pendingRewards.get(userId) || new Map()).size
    });
  }
);

// Get leaderboard for a level
app.get('/api/leaderboard/:levelId',
  authenticateToken,
  param('levelId').isInt({ min: 1, max: Object.keys(LEVEL_CONFIG).length }),
  handleValidationErrors,
  (req, res) => {
    const levelId = parseInt(req.params.levelId, 10);
    const leaderboard = [];

    for (const [userId, completions] of levelCompletions) {
      const user = users.get(userId);
      if (!user || user.flagged) continue;

      const levelBest = completions
        .filter(c => c.levelId === levelId)
        .reduce((best, c) => {
          if (!best || c.serverValidatedScore > best.serverValidatedScore) return c;
          return best;
        }, null);

      if (levelBest) {
        leaderboard.push({
          username: user.username,
          score: levelBest.serverValidatedScore,
          stars: levelBest.stars,
          time: Math.round(levelBest.serverMeasuredTime)
        });
      }
    }

    leaderboard.sort((a, b) => b.score - a.score);

    res.json({
      levelId,
      leaderboard: leaderboard.slice(0, 100)
    });
  }
);

